_CAR = re.compile(r'(?<![가-힣\d])\s*(\d{2,3}\s*[가-힣]\s*\d{4})(?!\d)')
_CAR_REGION = re.compile(
    r'(?<![가-힣])'
    r'(서울|부산|대구|인천|광주|대전|울산|세종|경기|강원|충북|충남|전북|전남|경북|경남|제주)'
    r'\s*(\d{2,3}[가-힣]\d{4})(?!\d)'
)
_VEHICLE_KEYWORDS = (
    r'차량번호|차번호|차량|번호판|자동차|승용차|트럭|버스|오토바이|이륜차|'
    r'렌트카|렌터카|영업용|자가용|주차|접촉사고|사고차량|가해차량|피해차량|'
    r'배달|퀵서비스|택배|택시|화물차|덤프트럭|차량정보|차번|plate'
)
_VEHICLE_KEYWORD_PATTERN = re.compile(r'(?:' + _VEHICLE_KEYWORDS + r')[\s:：\-]*', re.IGNORECASE)

def detect_vehicle(text: str) -> list:
    results = []
    matched_spans = []

    for kw_match in _VEHICLE_KEYWORD_PATTERN.finditer(text):
        after_kw = kw_match.end()
        remaining = text[after_kw:]
        m = _CAR_REGION.match(remaining)
        if m:
            real_span = (after_kw + m.start(), after_kw + m.end())
            if _no_overlap(real_span, matched_spans):
                results.append({"type": "차량번호", "value": m.group(), "span": real_span})
                matched_spans.append(real_span)
                continue
        m = _CAR.match(remaining)
        if m:
            real_span = (after_kw + m.start(), after_kw + m.end())
            if _no_overlap(real_span, matched_spans):
                results.append({"type": "차량번호", "value": m.group(), "span": real_span})
                matched_spans.append(real_span)

    for m in _CAR_REGION.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "차량번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    for m in _CAR.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "차량번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    results.sort(key=lambda x: x["span"][0])
    return results


