def detect_accounts(text: str) -> list:
    results = []
    matched_spans = []

    for m in _ACC_PATTERNS["domestic_account_keyword"].finditer(text):
        value = m.group(1)
        span = m.span(1)
        if _no_overlap(span, matched_spans):
            results.append({"type": "계좌번호", "value": value, "span": span})
            matched_spans.append(span)

    for m in _ACC_PATTERNS["domestic_account"].finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "계좌번호", "value": m.group(), "span": span})
            matched_spans.append(span)

    return results


