# < 마스킹 태그 매핑 함수 >────────────────────────────
def make_mask(dtype: str, value: str = "") -> str:
    """탐지 타입을 카테고리 태그로 완전 치환"""

    if "전화번호" in dtype :
        return "[전화번호]"
    if "주민등록번호" in dtype :
        return "[주민등록번호]"
    if "외국인등록번호" in dtype :
        return "[외국인등록번호]"
    if "카드번호" in dtype or "CARD" in dtype:
        return "[카드번호]"
    if "계좌번호" in dtype :
        return "[계좌번호]"
    if "이메일" in dtype :
        return "[이메일]"
    if "여권번호" in dtype :
        return "[여권번호]"
    if "사업자등록번호" in dtype :
        return "[사업자등록번호]"
    if "법인등록번호" in dtype :
        return "[법인등록번호]"
    if "차량번호" in dtype :
        return "[차량번호]"
    '''if "IPv4" in dtype or "IP" in dtype:
        return "[IPv4주소]"
    if "IPv6" in dtype or "IP" in dtype:
        return "[IPv6주소]"'''
    if "현금영수증번호" in dtype :
        return "[현금영수증번호]"

    return ""


# < 마스킹 처리 함수 > ────────────────────────────────────
# 마스킹 처리 함수

def mask_text(text: str, detections: list) -> str:
    """탐지 결과를 받아 원본 텍스트를 마스킹 처리"""
    # 뒤에서부터 치환해야 span 위치가 밀리지 않음
    sorted_detections = sorted(detections, key=lambda x: x["span"][0], reverse=True)

    result = text # 원본을 복사해서 씀
    for det in sorted_detections:
        start, end = det["span"]
        masked = make_mask(det["type"]) # 탐지된 타입을 태그 문자열로 바꿔줌 - 마스킹 카테고리 태그
        result = result[:start] + masked + result[end:]

    return result # 마스킹 된 텍스트만 변환


# ──────────────────────────────────────────
# 통합 진입 함수 (API에서 호출)

def detect_and_mask(text: str) -> dict:
    detections = detect_all(text)
    masked = mask_text(text, detections)
    # 리스크 판단을 위한 엔티티 생성
    entities = [
            DetectedEntity(
                original=d["value"],
                masked=make_mask(d["type"]),
                entity_type=d["type"],
                start=d["span"][0],
                end=d["span"][1],
                stage="regex",
                risk_level=_get_risk(d["type"]),  # 타입 기반 초기 리스크 부여
            )
            for d in detections
        ]

    return {"masked": masked, "detections": entities}